class Queue:
    def __init__(self):
        self.queue = []

    def enqueue(self, x):
        self.queue.append(x)

    def dequeue(self):
        if not self.queue:
            raise ValueError('Queue is empty')
        return self.queue.pop(0)

solutions.cpp:
class Queue {
public:
    void enqueue(int x) {
        queue.push_back(x);
    }
    int dequeue() {
        if (queue.empty()) {
            throw std::runtime_error("Queue is empty");
        }
        int front = queue.front();
        queue.pop_front();
        return front;
    }

private:
    std::deque<int> queue;
};
